var e=[{id:`L33_1`,type:`dialog`,speaker:`CEO_NPC_ALPHA_NULL`,text:{KOREA:`지아야……? 지아 왔니?`,JPN:`ユイ……？　そこにいるのはユイか？`,ENG:`Jia...? Is that you?`,TWN:`小佳……？是小佳嗎？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L34_1`,type:`dialog`,speaker:`CEO_NPC_ALPHA_NULL`,text:{KOREA:`쿨럭, 쿨럭……. 이젠…… 앞도 잘 안 보이는구나.`,JPN:`ゴホッゴホッ……もはや……目も見えなくなったか。`,ENG:`*Cough, cough!* My eyesight... It’s not what it used to be`,TWN:`咳咳咳……我的眼睛……現在連眼前的東西也看不清楚呢。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L40_1`,type:`dialog`,speaker:`AUNT_NPC_ALPHA_QM`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L42_1`,type:`dialog`,speaker:`CEO_NPC_ALPHA_NULL`,text:{KOREA:`링거는 놔둬도 괜찮다……. 간호사가 방금 막 왔다 갔어.`,JPN:`点滴は大丈夫だ……看護師がさっき来たばかりでな。`,ENG:`Leave it be... The nurse was here a second ago.`,TWN:`不用管點滴……護士剛才才來換過而已。`},stage:{bg:`HOSPITAL`,slots:{L:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L43_1`,type:`dialog`,speaker:`AUNT_NPC_ALPHA_QM`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L44_1`,type:`dialog`,speaker:`CEO_NPC_ALPHA_NULL`,text:{KOREA:`지아야……?`,JPN:`ユイ……？`,ENG:`Jia...?`,TWN:`小佳……？`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L45_1`,type:`dialog`,speaker:`AUNT_NPC_ALPHA_QM`,text:{KOREA:`그 놈의 지아…… 지아…… 지아!`,JPN:`いつも、いつも、ユイ……ユイ……ユイ！`,ENG:`It’s always Jia... Jia... Jia!!!`,TWN:`小佳……小佳……小佳！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L46_1`,type:`dialog`,speaker:`AUNT_NPC_ALPHA_QM`,text:{KOREA:`작작 좀 해, 아빠. 어차피 걔도 나처럼 진짜 손녀가 아니잖아.`,JPN:`もういい加減にして、父さん！　どうせあの子も私と同じく実の孫じゃないでしょ！`,ENG:`Daddy, will you please stop! She’s not even your real family!`,TWN:`夠了沒啊，爸！她和我一樣，都不是你親生的！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L47_1`,type:`dialog`,speaker:`CEO_NPC_ALPHA_NULL`,text:{KOREA:`너…… 그 목소리……!`,JPN:`お前……その声は……！`,ENG:`You... That voice...!`,TWN:`你……你的聲音……！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L48_1`,type:`dialog`,speaker:`CEO_NPC_ALPHA_NULL`,text:{KOREA:`네가, 네가 어떻게 감히 여길……! 쿨럭……! 커흑……!`,JPN:`お前が、お前がどうしてここに……！　ゴホッ！　ゴホッ！`,ENG:`You... How dare you come here...! *Cough...!* Gaaagh...!`,TWN:`你…你竟敢到這裡來……！咳咳……！咳咳……！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L49_1`,type:`dialog`,speaker:`AUNT_NPC_ALPHA_QM`,text:{KOREA:`아빠한테 고맙다고 인사하러 왔지. 돈 좀 날렸다고 날 교도소에 처박아 줬잖아.`,JPN:`父さんにお礼を言いに来たの。ちょっと金を無駄にしたからって、私を刑務所に閉じ込めてくれたでしょ。`,ENG:`I came here to say thank you. You know, for sending me to prison because I lost some money?`,TWN:`我是來謝謝爸的，不是你花錢把我送進監獄的嗎！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L50_1`,type:`dialog`,speaker:`AUNT_NPC_ALPHA_QM`,text:{KOREA:`덕분에 <color=#ffd34c>새 친구</color>들도 사귀고 참 좋은 경험이었어.`,JPN:`おかげで<color=#ffd34c>新しい友達</color>もできて、
とても素敵な経験だったわ。`,ENG:`Thanks to you, I had a good time and made some <color=#ffd34c>new friends</color>.`,TWN:`托爸的福，我才能交到<color=#ffd34c>新朋友</color>，這真是個很棒的經驗呢～`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},R:null}}},{id:`L1_1`,type:`dialog`,speaker:`CEO_NPC_ALPHA_NULL`,text:{KOREA:`무슨 꿍꿍이냐……! 내가, 두 번 다시 얼씬도 하지 말랬거늘……!`,JPN:`何を企んでいる……！　二度と顔を見せるなと言ったはずだ……！`,ENG:`What are you up to now...?! I told you to never show your face around me again...!!`,TWN:`你想幹嘛……！我不是叫你別再出現在我面前嗎……！`},stage:{bg:`HOSPITAL`,slots:{L:null,C:{char_id:`AUNT_NPC_ALPHA_QM`,face:`UNIT_IDLE`},R:null}}}];export{e as default};